class WrappingRuleReproduceTest {
    private val wrappingRuleAssertThat = assertThatRule { WrappingRule() }

    @Test
    fun `issue reproduction single line`() {
        val code = """
            val foo = { size -> icon?.getBitmap(size)?.await() }
        """.trimIndent()

        wrappingRuleAssertThat(code)
            .addAdditionalRuleProvider { IndentationRule() }
            .hasNoLintViolations()
    }

    @Test
    fun `issue reproduction multiline body but single line parameters`() {
        val code = """
            val foo = { size -> 
                icon?.getBitmap(size)?.await() 
            }
        """.trimIndent()

        wrappingRuleAssertThat(code)
            .addAdditionalRuleProvider { IndentationRule() }
            .hasNoLintViolations()
    }

    @Test
    fun `wrapped parameters should enforce newline`() {
        val code = """
            val foo = { size,
                other ->
                icon?.getBitmap(size)?.await()
            }
        """.trimIndent()

        val formattedCode = """
            val foo = {
                size,
                other ->
                icon?.getBitmap(size)?.await()
            }
        """.trimIndent()

        wrappingRuleAssertThat(code)
            .addAdditionalRuleProvider { IndentationRule() }
            .hasLintViolations(
                LintViolation(1, 13, "Missing newline after \"{\"")
            )
            .isFormattedAs(formattedCode)
    }
}
